                                               \"/images/imagen-no-disponible.jpg\",\n                                                alt: \"User Img\"\n                                              }\n                                            })\n                                          ]\n                                        : [\n                                            _c(\"img\", {\n                                              staticClass: \"thumbail\",\n                                              attrs: {\n                                                src: _vm.formatUrlImage(\n                                                  data.image\n                                                )\n                                              }\n                                            })\n                                          ]\n                                    ],\n                                    2\n                                  )\n                                ])\n                              ]),\n                              _vm._v(\" \"),\n                              _c(\"div\", [\n                                _vm._v(\n                                  \"\\n                                        \" +\n                                    _vm._s(data.code) +\n                                    \"\\n                                    \"\n                                )\n                              ]),\n                              _vm._v(\" \"),\n                              _c(\n                                \"div\",\n                                {\n                                  staticClass:\n                                    \"d-flex flex-column align-items-end\"\n                                },\n                                [\n                                  _c(\"div\", { staticClass: \"block mb-2\" }, [\n                                    _c(\n                                      \"span\",\n     