         <div class=\"col-6 \">\r\n                <h2 class=\"text-muted text-small\">\r\n                    Buscar\r\n                </h2>\r\n                <template v-if=\"selectOption == 4\">\r\n                    <el-input ref=\"input_items\" size=\"small\" v-model=\"input_itemMobil\" @input=\"emitData()\"\r\n                        @focus=\"clear_input()\" autofocus placeholder=\"Ingrese aca Un Producto\">\r\n                        <el-button slot=\"append\" icon=\"el-icon-search\" @click=\"emitData\" ></el-button>\r\n                    </el-input>\r\n                </template>\r\n\r\n                <template v-else>\r\n                    <el-input ref=\"input_itemMobil\" size=\"small\" v-model=\"input_itemMobil\" @input=\"emitData()\"\r\n                        @focus=\"clear_input()\" autofocus placeholder=\"Ingrese aca Un Producto\">\r\n                        <el-button slot=\"append\" icon=\"el-icon-search\" @click=\"emitData\"></el-button>\r\n                    </el-input>\r\n                </template>\r\n            </div>\r\n        </div>\r\n        <div class=\"row\">\r\n            <div class=\"col-6 col-lg-4 col-xl-4 col-xxl-4 p-1\" v-for=\"(data, index) in foods\" :key=\"index\">\r\n                        <el-tooltip effect=\"dark\" :disabled=\"\r\n                            data.item.warehouses.length == 1 ||\r\n                            !configuration.show_stock_establishment_box\r\n                        \">\r\n                            <div slot=\"content\">\r\n                                Stock Almacenes <br />\r\n                                <span v-for=\"(info, idx) in data.item.warehouses\" :key=\"idx\">\r\n                                    <label v-if=\"info.warehouse.id != establishmentId\">\r\n                                        <template v-if=\"data.item.max_quantity\">\r\n                                            <!-- {{\r\n                                                `${\r\n                                                    info.warehouse.description\r\n                                                }: ${Number(info.stock) /\r\n                                                    data.item.max_quantity}`\r\n                                            }} -->\r\n                                            {{ formatedStockPresentation(data.item, info.stock) }}\r\n                                        </template>\r\n                                        <template v-else>\r\n                                            {{\r\n                                            `${info.warehouse.description}: ${Number(\r\n                                                info.stock\r\n                                            ).toFixed(2)}`\r\n                                            }}\r\n                                        </template> </label><br />\r\n                                </span>\r\n                            </div>\r\n                            <div id=\"card\" class=\"\r\n                                        overflow-hidden\r\n                                        coupon\r\n                                        rounded\r\n                                        d-flex\r\n                                        flex-column\r\n                                        justify-content-between\r\n                                        p-1\r\n                                        \">\r\n                                <div @click=\"addFood(index)\">\r\n                                    <div>\r\n                                        <span class=\"lead-font-weight-700 h5\">\r\n                                            {{ data.description.toUpperCase() }}\r\n                                        </span>\r\n                                    </div>\r\n                                    <div class=\"d-flex align-items-end justify-content-between\">\r\n                                        <div class=\"p-1\">\r\n                                            <div class=\"icon-container\">\r\n                                                <div class=\"icon-container_box\">\r\n                                                    <template v-if=\"data.image == 'imagen-no-disponible.jpg'\">\r\n                                                        <img hidden src=\"/images/imagen-no-disponible.jpg\"\r\n                                                            alt=\"User Img\" class=\"thumbail\" />\r\n                                                    </template>\r\n                                                    <template v-else>\r\n                                                        <img :src=\"formatUrlImage(data.image)\" class=\"thumbail\" />\r\n                                                    </template>\r\n                                                </div>\r\n                                            </div>\r\n                                        </div>\r\n                                        <div>\r\n                                            {{ data.code }}\r\n                                        </div>\r\n                                        <div class=\"d-flex flex-column align-items-end\">\r\n                                            <!-- <div class=\"text-uppercase font-weight-light h5\">\r\n                        {{ data.category.name }}\r\n                      </div> -->\r\n                                            <div class=\"block mb-2\">\r\n                                                <span class=\"time font-weight-light\">\r\n                                                    <span class=\"text-muted lead-font-weight-700\">\r\n                                                        S/\r\n                                                        {{ data.price }}</span>\r\n                                                </span>\r\n                                            </div>\r\n                                            <div>\r\n                                                <template v-if=\"data.item.stock > 0\">\r\n                                                    <span class=\"badge rounded-pill bg-primary m-l-0\">Stock\r\n                                                        <template v-if=\"data.item.max_quantity\">\r\n                                                            {{\r\n                                                                formatedStockPresentation(\r\n                                                                    data.item,\r\n                                                                data.item.stock\r\n                                                                                                                        )\r\n                                                            }}\r\n                                                            <!-- {{\r\n                                                                parseFloat(\r\n                                                                    data.item\r\n                                                                        .stock /\r\n                                                                        data\r\n                                                                            .item\r\n                                                                            .max_quantity\r\n                                                                )\r\n                                                            }} -->\r\n                                                        </template>\r\n                                                        <template v-else>\r\n                                                            {{ parseFloat(data.item.stock) }}\r\n                                                        </template>\r\n                                                    </span>\r\n                                                </template>\r\n                                                <template v-else>\r\n                                                    <span class=\"badge rounded-pill bg-danger m-l-0\">\r\n                                                        Agotado\r\n                                                    </span>\r\n                                                </template>\r\n                                            </div>\r\n                                        </div>\r\n                                    </div>\r\n                                </div>\r\n                                <div @click=\"nthing\" v-if=\"data.types.length > 0\" class=\"d-flex justify-content-end\"\r\n                                    style=\"padding-right: 10px; margin-top: 5px\">\r\n                                    <el-dropdown @command=\"clickCommand\">\r\n                                        <span class=\"el-dropdown-link\">\r\n                                            Precios<i class=\"el-icon-arrow-down el-icon--right\"></i>\r\n                                        </span>\r\n                                        <el-dropdown-menu slot=\"dropdown\">\r\n                                            <el-dropdown-item v-for=\"(type, idx) in data.types\" :key=\"idx\"\r\n                                                :command=\"type\">\r\n                                                {{ formatDescriptionType(type) }}\r\n                                            </el-dropdown-item>\r\n                                        </el-dropdown-menu>\r\n                                    </el-dropdown>\r\n                                </div>\r\n                            </div>\r\n                        </el-tooltip>\r\n                    </div>\r\n        </div>\r\n        <div class=\"row\">\r\n            <div class=\"col-6\"><el-button @click=\"close\">Cancel</el-button></div>\r\n            \r\n            \r\n            \r\n        </div>\r\n\r\n    </el-dialog>\r\n\r\n\r\n\r\n</template>\r\n\r\n<script>\r\n    \r\nexport default ({\r\n    props: [\r\n        \"foods\",\r\n        \"configuration\",\r\n        \"worker\",\r\n        \"pagination\",\r\n        \"blockAdd\",\r\n        \"localOrden\",\r\n        \"category\",\r\n        \"categories\",\r\n        \"showDialogViewItems\",\r\n        \"selectOption\"\r\n    ],\r\n    data(){\r\n        return {\r\n            selectCategory: 0,\r\n            activeName: \"menu\",\r\n            loading: true,\r\n            ordenItems: [],\r\n            orden: [],\r\n            currentFood: {},\r\n            item: null,\r\n            search: \"Buscar por Codigo\",\r\n            currentImage: null,\r\n            showImage: false,\r\n            listFoods: [],\r\n            selectedFood: null,\r\n            allFalse: true,\r\n            title: null,\r\n            total: null,\r\n            ordenId: null,\r\n            optionsSelected: 0,\r\n            generalOrdens: 1,\r\n            establishmentId: this.worker.establishment_id,\r\n            settings: {\r\n                dots: false,\r\n                dotsClass: \"slick-dots custom-dot-class\",\r\n                edgeFriction: 0.35,\r\n                infinite: false,\r\n                speed: 500,\r\n                centerMode: true,\r\n                centerPadding: \"10px\",\r\n                focusOnSelect: true,\r\n                infinite: true,\r\n                slidesToShow: 3,\r\n                slidesToScroll: 3,\r\n                swipeToSlide: true,\r\n                speed: 500,\r\n                responsive: [\r\n                    {\r\n                        breakpoint: 1024,\r\n                        settings: {\r\n                            slidesToShow: 3,\r\n                            slidesToScroll: 3,\r\n                            infinite: true,\r\n                            dots: true,\r\n                        },\r\n                    },\r\n                    {\r\n                        breakpoint: 600,\r\n                        settings: {\r\n                            slidesToShow: 2,\r\n                            slidesToScroll: 2,\r\n                            initialSlide: 2,\r\n                        },\r\n                    },\r\n                    {\r\n                        breakpoint: 480,\r\n                        settings: {\r\n                            slidesToShow: 1,\r\n                            slidesToScroll: 1,\r\n                        },\r\n                    },\r\n                ],\r\n            },\r\n            settings_tables: {\r\n                dots: true,\r\n                dotsClass: \"slick-dots custom-dot-class\",\r\n                infinite: false,\r\n                speed: 500,\r\n                centerMode: true,\r\n                centerPadding: \"10px\",\r\n                focusOnSelect: true,\r\n                infinite: true,\r\n                slidesToShow: 5,\r\n                slidesToScroll: 5,\r\n                swipeToSlide: true,\r\n                responsive: [\r\n                    {\r\n                        breakpoint: 1024,\r\n                        settings: {\r\n                            slidesToShow: 2,\r\n                            slidesToScroll: 2,\r\n                            infinite: true,\r\n                            dots: true,\r\n                        },\r\n                    },\r\n                    {\r\n                        breakpoint: 600,\r\n                        settings: {\r\n                            slidesToShow: 2,\r\n                            slidesToScroll: 2,\r\n                            initialSlide: 2,\r\n                        },\r\n                    },\r\n                    {\r\n                        breakpoint: 480,\r\n                        settings: {\r\n                            slidesToShow: 2,\r\n                            slidesToScroll: 2,\r\n                        },\r\n                    },\r\n                ],\r\n            },\r\n            screenWidth: 0,\r\n            input_itemMobil:\"\",\r\n            categoryChild: \"\"\r\n        }\r\n    },\r\n    mounted() {\r\n        this.screenWidth = window.innerWidth;\r\n        window.addEventListener('resize', this.handleResize);\r\n\r\n        if (this.foods.length > 0) {\r\n            this.loading = false;\r\n        }\r\n    },\r\n    watch: {\r\n        foods(__, _) {\r\n            this.updateListFoods();\r\n        },\r\n    },\r\n    created() {\r\n        this.ordenItems = [];\r\n        this.orden = [];\r\n        this.updateListFoods();\r\n    },\r\n\r\n    methods: {\r\n        UpdateparentCategory(){\r\n           this.$emit(\"update:category\",this.categoryChild)\r\n            this.$emit('data-received', this.input_itemMobil)\r\n        },\r\n        \r\n        emitData(){\r\n            //this.$emit(\"update:category\")\r\n            if(this.input_itemMobil.length > 2){\r\n                this.$emit('data-received', this.input_itemMobil)\r\n            }\r\n            \r\n        },\r\n        \r\n        handleResize() {\r\n            this.screenWidth = window.innerWidth\r\n        },\r\n        nthing() { },\r\n        getDefaultPrice(type) {\r\n            let listPricesDescription = [\"price1\", \"price2\", \"price3\"];\r\n            let currentPriceIndx = listPricesDescription[type.price_default - 1];\r\n            let price = type[currentPriceIndx];\r\n            if (type.total == null) {\r\n                this.$toast.error(\r\n                    \"Politica de precio sin total: Tomando precio unitario..\"\r\n                );\r\n            } else {\r\n                price = Number(type.total);\r\n            }\r\n            return price;\r\n        },\r\n        formatDescriptionType(type) {\r\n            let price = this.getDefaultPrice(type);\r\n            return `${type.description} (${Number(\r\n                type.quantity_unit\r\n            )}) - S/ ${price}`;\r\n        },\r\n\r\n        clickCommand(type) {\r\n            let idxFood = this.listFoods.findIndex(\r\n                (food) => food.item.id == type.item_id\r\n            );\r\n            if (idxFood >= 0) {\r\n                this.addFood(idxFood, type);\r\n            }\r\n        },\r\n        updateListFoods() {\r\n            this.listFoods = this.foods.map((f) => {\r\n                return { ...f, select: false };\r\n            });\r\n\r\n        },\r\n        formatedStockPresentation(\r\n            {\r\n                max_quantity,\r\n                item_unit_types,\r\n\r\n                unit_type,\r\n            },\r\n            stock\r\n        ) {\r\n            let general = Math.trunc(stock / max_quantity);\r\n            let part = ((stock / max_quantity) % 1).toFixed(2);\r\n\r\n            let text = `${general} ${unit_type.id}`;\r\n            if (part != 0) {\r\n                let item_unit = item_unit_types.find(\r\n                    (i) => Number(i.quantity_unit) == Number(max_quantity)\r\n                );\r\n                if (item_unit) {\r\n                    text += ` ${part * max_quantity} ${item_unit.unit_type.id}`;\r\n                }\r\n            }\r\n\r\n            return text;\r\n        },\r\n        getRecords() {\r\n            let currentPage = this.pagination.current_page;\r\n            this.$emit(\"changePage\", currentPage);\r\n        },\r\n        deleteOrden(id) {\r\n            this.ordenItems = this.ordenItems.filter((o) => o.id != id);\r\n        },\r\n        calculateOrden() {\r\n            // this.$refs.ordenRef.calculateTotal();\r\n        },\r\n        selectSearch(value) {\r\n            this.optionsSelected = value;\r\n        },\r\n\r\n        deleteFood(idx) {\r\n            this.orden.splice(idx, 1);\r\n        },\r\n        setCategory(id) {\r\n            this.selectCategory = id;\r\n            !this.allFalse && this.setFalse();\r\n            if (id == 0) {\r\n                this.listFoods = this.foods;\r\n            } else {\r\n                this.listFoods = [];\r\n                this.listFoods = _.filter(this.foods, { category_food_id: id });\r\n            }\r\n        },\r\n        addFood(index = 0, type = null) {\r\n            if (this.blockAdd && !this.configuration.box_orden) {\r\n                this.$toast.error(\"No puede agregar productos a esta orden.\");\r\n                return;\r\n            }\r\n            this.selectedFood = JSON.parse(JSON.stringify(this.listFoods[index]));\r\n\r\n            if (!this.selectedFood) return;\r\n\r\n            if (\r\n                Number(this.selectedFood.item.stock) <= 0 &&\r\n                this.configuration.sales_stock == true\r\n            ) {\r\n                this.$toast.warning(\"Stock insuficiente\");\r\n                return;\r\n            }\r\n            let foodFound = this.localOrden.filter(\r\n                (f) => f.id == this.selectedFood.id\r\n            );\r\n\r\n            if (foodFound.length != 0) {\r\n                let { item } = this.selectedFood;\r\n                if (item.lots_enabled) {\r\n                    if (item.item_unit_types.length == 0) {\r\n                        let message = \"Producto con lote, ya  agregado\";\r\n                        this.$toast.warning(message);\r\n                        return;\r\n                    }\r\n                }\r\n\r\n                if (item.series_enabled) {\r\n                    if (item.item_unit_types.length == 0) {\r\n                        let message = \"Producto con serie, ya  agregado\";\r\n                        this.$toast.warning(message);\r\n                        return;\r\n                    } else {\r\n                        if (type) {\r\n                            if (foodFound.some((i) => i.type_id == type.id)) {\r\n                                let message = \"Producto con serie, ya  agregado\";\r\n                                this.$toast.warning(message);\r\n                                return;\r\n                            }\r\n                        }\r\n                    }\r\n                }\r\n                let qty = foodFound.reduce((a, b) => a + Number(b.quantity), 0);\r\n\r\n                if (type) {\r\n                    // qty += Number(type.quantity_unit);\r\n\r\n                    qty += 1;\r\n                } else {\r\n                    qty += 1;\r\n                }\r\n                if (this.configuration.sales_stock == true) {\r\n                    if (qty > Number(this.selectedFood.item.stock)) {\r\n                        this.$toast.warning(\"Limite de stock alcanzado\");\r\n                        return;\r\n                    }\r\n                }\r\n            } else {\r\n                if (type) {\r\n                    let qty = type.quantity_unit;\r\n                    if (this.configuration.sales_stock == true) {\r\n                        let stock = Number(this.selectedFood.item.stock);\r\n                        if (qty == stock || qty > stock) {\r\n                            this.$toast.warning(\"Limite de stock alcanzado\");\r\n                            return;\r\n                        }\r\n                    }\r\n                }\r\n            }\r\n\r\n            this.currentFood = {\r\n                id: this.selectedFood.id,\r\n                food: this.selectedFood,\r\n                observation: null,\r\n                price: this.selectedFood.price,\r\n                quantity: !!this.selectedFood.item.series_enabled ? 0 : 1,\r\n            };\r\n            this.$emit(\"insertOrden\", this.currentFood, this.selectedFood.id, type);\r\n            this.$notify({\r\n                title: this.currentFood.food.description.toLowerCase(),\r\n                duration: 800,\r\n                iconClass: \"el-icon-food\",\r\n                message: \"Agregado con èxito\",\r\n                position: \"bottom-left\",\r\n            });\r\n\r\n            this.currentFood = {\r\n                food: null,\r\n                observation: null,\r\n                quantity: 0,\r\n                price: 0,\r\n            };\r\n            this.selectedFood = null;\r\n            this.item = null;\r\n            //this.setFalse();\r\n            //this.$emit(\"buscarnuevo\");\r\n            //this.$forceUpdate();\r\n        },\r\n        setFalse() {\r\n            this.listFoods = this.listFoods.map((f) => {\r\n                f.select = false;\r\n                return f;\r\n            });\r\n            this.allFalse = true;\r\n        },\r\n        selectFood(index) {\r\n            //  this.$refs.description.$el.getElementsByTagName(\"input\")[0].focus();\r\n            if (this.listFoods[index].select) {\r\n                this.listFoods[index].select = false;\r\n                this.allFalse = true;\r\n                this.selectedFood = null;\r\n                return;\r\n            }\r\n\r\n            !this.allFalse && this.setFalse();\r\n            this.listFoods[index].select = true;\r\n            this.selectedFood = this.listFoods[index];\r\n            this.allFalse = false;\r\n        },\r\n        searchFoodCategories(value) {\r\n            if (value == 0) {\r\n                this.listFoods = this.foods;\r\n            } else {\r\n                this.listFoods = _.filter(this.foods, {\r\n                    category_food_id: value,\r\n                });\r\n            }\r\n        },\r\n        searchFood(value = null, optionsSelected = \"Descripcion\") {\r\n            !this.allFalse && this.setFalse();\r\n            if (value) {\r\n                if (optionsSelected == \"Descripcion\") {\r\n                    this.listFoods = this.foods.filter((f) =>\r\n                        f.description.toLowerCase().includes(value)\r\n                    );\r\n                } else {\r\n                    //this.listFoods=_.filter(this.foods,{'code':value})\r\n                    this.listFoods = this.foods.filter((ff) =>\r\n               